property_tests.invariant_check:
makefile = read_file('Makefile')
for target in ['web-dev', 'web-build']:
  body = extract_target(makefile, target)
  // Verify bounded: install check executes at most once (no retry loop)
  install_occurrences = count_occurrences(body, 'npm install')
  assert install_occurrences <= 1, 'npm install must not be retried in a loop'
  // Verify ordering: install always precedes run
  assert position_of(body, 'npm install') < position_of(body, 'npm run')
  // Verify conditional: node_modules check gates the install
  assert 'node_modules' in body

makefile = read_file('Makefile')
for target in ['web-dev', 'web-build']:
  body = extract_target(makefile, target)
  // Ensure no '- ' prefix (which tells make to ignore errors)
  assert NOT any_line_starts_with_dash_space(body)
  assert NOT 'exit 0' forced after npm commands
// Behavioral: simulate failures
for script in ['build', 'lint']:
  result = run_npm_script_with_forced_exit_code(script, exit_code=1)
  assert result.exit_code == 1
  assert result.exit_code != 0

edge_case_tests.assertion_pseudocode:
// Static check
doc = read_file('docs/web-ui.md')
assert 'Node' in doc AND '18' in doc
// Dynamic check (requires environment with old Node)
result = run_command('npm install', cwd='web/', node_version='16')
assert result.exit_code != 0 OR result.stderr contains version error
// OR engines field check
pkg = read_json('web/package.json')
assert pkg.get('engines', {}).get('node') specifies '>=18'
